async function loadGatewayUser(req, res, next) {
  try {
    if (!req.session?.userId) return next();

    const user = await db.findUser(req.session.userId);
    if (!user) return next();

    user.flags = await flags.load(user.id);
    await audit.log('gateway.user.loaded', { userId: user.id });

    req.user = user;
    next();
  } catch (err) {
    return next(err);
  }
}
```

Notes:
- Order preserved: `session_check` → `db.findUser` → `flags.load` → `audit.log` → `next`.
- Any thrown error (including from `db.findUser`) routes via `next(err)`.
- Verify callers no longer rely on a sync signature and that `db.findUser`/`flags.load`/`audit.log` return promises.
